module RefModule(
    input wire clk,
    input wire reset,
    input wire signal,
    output reg crossing
);
reg obf_previous_signal;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        obf_previous_signal <= 0;
        crossing <= 0;
    end else begin
        crossing <= (obf_previous_signal && !signal) || (!obf_previous_signal && signal);
        obf_previous_signal <= signal;
    end
end
endmodule
